const docs = [
    'Node-RED is a programming tool for wiring together hardware devices, APIs and online services.',
    'LangChain is a framework for developing applications powered by language models.',
    'MCP (Model Context Protocol) is an open protocol that enables seamless integration between LLM applications and external data sources and tools.',
    'ReAct is a paradigm where LLMs generate reasoning traces and task-specific actions.'
];

// Нода vectorstore с collection "kb-complex" ищет данные в global.get('langchain_vs_kb-complex')
const key = 'langchain_vs_kb-complex';
const raw = global.get(key) || [];
global.set(key, raw.concat(docs));

msg.payload = { ok: true, added: docs.length, total: raw.length + docs.length };
return msg;
